    43→    AST prog = parseExp();
    44→    Token t = in.readToken();
    45→    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "'followed by extra token " + t);
    46→    
    47→    /* Invoke the CheckVisitor confirm prog does not contain free variables or parameter lists with duplicate names. */
    48→    prog.accept(CheckVisitor.INITIAL);   // aborts on an error by throwing an exception
