   102→      if (! op.isUnOp()) error(op,"unary operator");
   103→      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
   104→    }
   105→    
   106→    if (token instanceof Constant) return (Constant) token;
   107→    
   108→    AST factor = parseFactor(token);
   109→    Token next = in.peek();
   110→    if (next == LeftParen.ONLY) {
   111→      in.readToken();  // remove next from input stream
   112→      AST[] exps = parseArgs();  // including closing paren
