private Def parseDef(Token var) {

  if (! (var instanceof Variable)) error(var, "variable");

  Token key = in.readToken();
  if (key != Lexer.BIND) error (key,"`:='");

  AST exp = parseExp();

  /* Semicolon is required unless the next token is `in' (which terminates the def list) */
  Token next = in.peek();
  if (next == SemiColon.ONLY) {
    in.readToken();  // consume the semicolon
  } else if (next != Lexer.IN) {
    error(next, "`;' or `in'");
  }
  // If followed by `in', leave it for parseDefs to read
  return new Def((Variable) var, exp);
}
